using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords =
    [
        "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "need", "dare", "ought",
        "used", "to", "of", "in", "for", "on", "with", "at", "by", "from",
        "as", "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further", "then",
        "once", "and", "but", "or", "nor", "not", "so", "yet", "both", "either",
        "neither", "each", "every", "all", "any", "few", "more", "most", "other",
        "some", "such", "no", "only", "own", "same", "than", "too", "very",
        "just", "because", "if", "when", "where", "how", "what", "which", "who",
        "whom", "this", "that", "these", "those", "i", "me", "my", "myself",
        "we", "our", "ours", "you", "your", "he", "him", "his", "she", "her",
        "it", "its", "they", "them", "their"
    ];

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency.
    /// </summary>
    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences but preserve their original order.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i].Trim()));

        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceBoundary()
            .Split(text)
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (StopWords.Contains(word.ToLowerInvariant()) || word.Length < 2)
                    continue;

                var lower = word.ToLowerInvariant();
                freq[lower] = freq.GetValueOrDefault(lower) + 1;
            }
        }

        // Normalize by the maximum frequency.
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys)
                freq[key] /= max;
        }

        return freq;
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            double score = 0;
            foreach (var word in words)
            {
                score += wordFrequencies.GetValueOrDefault(word.ToLowerInvariant());
            }

            scores.Add(words.Length > 0 ? score / words.Length : 0);
        }

        return scores;
    }

    private static string[] Tokenize(string sentence) =>
        WordToken().Matches(sentence).Select(m => m.Value).ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordToken();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _service.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

